#!/usr/bin/env ocaml
(* minigit: a minimal git-like version control system *)

let init_dir = ".minigit"
let index_file = init_dir ^ "/index"
let objects_dir = init_dir ^ "/objects"

let mkdir_p dir =
  let rec aux d =
    if Sys.file_exists d then ()
    else
      let parent = Filename.dirname d in
      if parent <> d then aux parent;
      Unix.mkdir d 0o755
  in
  aux dir

let write_file filename content =
  let oc = open_out filename in
  output_string oc content;
  close_out oc

let read_file filename =
  let ic = open_in filename in
  let n = in_channel_length ic in
  let s = really_input_string ic n in
  close_in ic;
  s

let sha1 s =
  let digest = Digest.string s in
  Digest.to_hex digest

let store_object content =
  let hash = sha1 content in
  let obj_path = Filename.concat objects_dir (String.sub hash 0 2) in
  mkdir_p obj_path;
  let obj_file = Filename.concat obj_path (String.sub hash 2 (String.length hash - 2)) in
  write_file obj_file content;
  hash

let cmd_init _ =
  if Sys.file_exists init_dir then
    (Printf.eprintf "minigit: repository already exists\n"; exit 1)
  else
    (mkdir_p init_dir;
     mkdir_p objects_dir;
     write_file index_file "";
     Printf.printf "Initialized empty minigit repository\n")

let cmd_add filename =
  if not (Sys.file_exists init_dir) then
    (Printf.eprintf "minigit: not a minigit repository\n"; exit 1);
  if not (Sys.file_exists filename) then
    (Printf.eprintf "minigit: %s: No such file or directory\n" filename; exit 1);
  let content = read_file filename in
  let hash = store_object content in
  let index_lines =
    if Sys.file_exists index_file then
      let lines = String.split_on_char '\n' (read_file index_file) in
      List.filter (fun line -> line <> "" && not (String.equal (String.sub line 0 (String.length filename)) filename)) lines
    else []
  in
  let new_index = String.concat "\n" (index_lines @ [filename ^ " " ^ hash]) ^ "\n" in
  write_file index_file new_index

let cmd_commit _ =
  if not (Sys.file_exists init_dir) then
    (Printf.eprintf "minigit: not a minigit repository\n"; exit 1);
  let index_content = read_file index_file in
  if String.trim index_content = "" then
    (Printf.eprintf "minigit: nothing to commit\n"; exit 1);
  let tree_entries = String.split_on_char '\n' index_content |>
                     List.filter (fun line -> String.trim line <> "") |>
                     List.map (fun line ->
                       match String.split_on_char ' ' line with
                       | [filename; hash] -> "100644 blob " ^ hash ^ "\t" ^ filename
                       | _ -> "")
  in
  let tree_content = String.concat "\n" tree_entries ^ "\n" in
  let tree_hash = store_object tree_content in
  let commit_content = "tree " ^ tree_hash ^ "\n" in
  let commit_hash = store_object commit_content in
  write_file index_file "";
  Printf.printf "Committed with tree " ^ tree_hash ^ "\n"

let () =
  if Array.length Sys.argv < 2 then
    (Printf.eprintf "usage: minigit <command> [<args>]\n"; exit 1);
  match Sys.argv.(1) with
  | "init" -> cmd_init ()
  | "add" ->
     if Array.length Sys.argv < 3 then
       (Printf.eprintf "usage: minigit add <file>\n"; exit 1);
     cmd_add Sys.argv.(2)
  | "commit" -> cmd_commit ()
  | cmd ->
     Printf.eprintf "minigit: unknown command '%s'\n" cmd;
     exit 1
